#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int N;
    while (scanf("%d", &N) == 1) {
        char **keys = (char**)malloc(N * sizeof(char*));
        char **vals = (char**)malloc(N * sizeof(char*));
        for (int i = 0; i < N; ++i) {
            char k[55], v[55];
            scanf("%s %s", k, v);
            keys[i] = strdup(k);
            vals[i] = strdup(v);
        }
        char query[55];
        scanf("%s", query);
        const char *ans = NULL;
        for (int i = 0; i < N; ++i) {
            if (strcmp(keys[i], query) == 0) { ans = vals[i]; break; }
        }
        if (ans) printf("%s\n", ans);
        else printf("Key not found\n");
        for (int i = 0; i < N; ++i) {
            free(keys[i]);
            free(vals[i]);
        }
        free(keys);
        free(vals);
    }
    return 0;
}

