#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    long long N;
    while (cin >> N) {
        unordered_map<string, string> mp;
        mp.reserve(N * 2);
        for (long long i = 0; i < N; ++i) {
            string key, val;
            cin >> key >> val;
            mp[key] = val; // later occurrences overwrite earlier ones
        }
        string query;
        cin >> query;
        auto it = mp.find(query);
        if (it != mp.end()) cout << it->second << '\n';
        else cout << "Key not found" << '\n';
    }
    return 0;
}

