#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().splitlines()
    idx = 0
    out = []
    while idx < len(data):
        if data[idx].strip() == "":
            idx += 1
            continue
        N = int(data[idx].strip())
        idx += 1
        d = {}
        for _ in range(N):
            key, val = data[idx].split()
            d[key] = val  # later values overwrite earlier ones
            idx += 1
        query = data[idx].strip()
        idx += 1
        try:
            out.append(d[query])
        except KeyError:
            out.append("Key not found")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

