const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\n/);
let idx = 0;
let outputs = [];
while (idx < input.length) {
  if (input[idx].trim() === '') { idx++; continue; }
  const N = parseInt(input[idx].trim(), 10);
  idx++;
  const map = new Map();
  for (let i = 0; i < N; i++) {
    const [k, v] = input[idx].trim().split(' ');
    map.set(k, v); // later entries overwrite earlier ones
    idx++;
  }
  const query = input[idx].trim();
  idx++;
  if (map.has(query)) outputs.push(map.get(query));
  else outputs.push('Key not found');
}
